-- ============================================
-- Legislacao full-site: Ataides Oliveira / Senado / projetos_lei
-- Seed completo do recorte: autoria parlamentar substantiva Senado 2011-2018
-- ============================================
-- DRAFT local: nao aplicar ao Supabase remoto sem autorizacao explicita.
--
-- Fonte oficial: Senado Federal Dados Abertos
--   https://legis.senado.leg.br/dadosabertos/senador/5164/autorias?formato=json
--   https://legis.senado.leg.br/dadosabertos/materia/{codigo}?formato=json
--   https://legis.senado.leg.br/dadosabertos/materia/autoria/{codigo}?formato=json
--   https://www25.senado.leg.br/web/atividade/materias/-/materia/{codigo}
--
-- Artefato de auditoria:
--   fonte interna de curadoria
--
-- Coverage:
--   coverage_id    = ataides-oliveira-senado-completo-autoria-substantiva-2011-2018-20260505
--   coverage_scope = inventario_completo_senado_autoria_substantiva_2011_2018_20260505
--
-- Filtro factual: endpoint senador/5164/autorias com IndicadorAutorPrincipal=Sim,
--   siglas substantivas em (PLS, PL, PEC, PLP, PRS, PDL, PDS, PCE), e
--   endpoint materia/autoria/{codigo} confirmando CodigoParlamentar=5164
--   com NumOrdemAutor=1. Resultado deste snapshot: 35 rows (31 PLS, 3 PEC, 1 PRS).
--
-- O recorte e completo apenas para a autoria parlamentar substantiva no Senado
-- retornada pelo endpoint oficial em 2026-05-05. Nao e inventario completo da
-- vida publica do candidato.
--
-- Esta migration NAO escreve em legislacao_mandato_executivo.
-- Esta migration NAO escreve em historico_politico.
-- Esta migration NAO popula tema, destaque, destaque_motivo nem situacao
--   (campos editoriais/curatoriais, fora do contrato bruto de ingest oficial).
-- Esta migration NAO promove UI/whitelist publica; isso exige novo fechamento.
-- ============================================

DO $$
DECLARE
  cand_id uuid;
  projetos_total int;
  target_count int;
  mandato_senado_count int;
BEGIN
  SELECT id INTO cand_id FROM candidatos WHERE slug = 'ataides-oliveira';

  IF cand_id IS NULL THEN
    RAISE NOTICE 'ataides-oliveira: candidato ausente neste banco local/CI minimo; seed projetos_lei Senado pulado';
    RETURN;
  END IF;

  SELECT count(*) INTO projetos_total
  FROM projetos_lei
  WHERE candidato_id = cand_id;

  SELECT count(*) INTO target_count
  FROM projetos_lei
  WHERE candidato_id = cand_id
    AND coverage_id = 'ataides-oliveira-senado-completo-autoria-substantiva-2011-2018-20260505';

  IF projetos_total NOT IN (0, 35) THEN
    RAISE EXCEPTION 'Pre-condicao ataides-oliveira: esperadas 0 rows atuais ou 35 rows alvo idempotentes em projetos_lei, encontradas %', projetos_total;
  END IF;

  IF projetos_total = 35 AND target_count <> 35 THEN
    RAISE EXCEPTION 'Pre-condicao ataides-oliveira: 35 rows existentes, mas apenas % com coverage_id alvo', target_count;
  END IF;

  SELECT count(*) INTO mandato_senado_count
  FROM historico_politico hp
  WHERE hp.candidato_id = cand_id
    AND COALESCE(hp.tipo_evento, 'mandato') = 'mandato'
    AND (hp.cargo ILIKE '%Senador%' OR hp.cargo_canonico = 'Senador')
    AND UPPER(COALESCE(hp.estado, '')) = 'TO'
    AND COALESCE(hp.periodo_inicio, 9999) <= 2011
    AND COALESCE(hp.periodo_fim, 0) >= 2018;

  IF mandato_senado_count < 1 THEN
    RAISE EXCEPTION 'Pre-condicao ataides-oliveira: mandato Senado/TO 2011-2019 nao encontrado em historico_politico';
  END IF;
END $$;

