WITH target AS (
  SELECT c.id AS candidato_id
  FROM candidatos c
  WHERE c.slug = 'ataides-oliveira'
)
INSERT INTO projetos_lei (
  candidato_id,
  tipo,
  numero,
  ano,
  ementa,
  fonte,
  proposicao_id_api,
  url_inteiro_teor,
  coverage_id,
  coverage_scope,
  metadata
)
SELECT
  target.candidato_id,
  seed.tipo,
  seed.numero,
  seed.ano,
  seed.ementa,
  seed.fonte,
  seed.proposicao_id_api,
  seed.url_inteiro_teor,
  seed.coverage_id,
  seed.coverage_scope,
  seed.metadata
FROM target
CROSS JOIN _seed_ataides_oliveira_senado_lote_a_projetos AS seed
ON CONFLICT (candidato_id, proposicao_id_api) DO NOTHING;

DO $$
DECLARE
  cand_id uuid;
  total_count int;
  target_count int;
  scope_count int;
  lme_count int;
BEGIN
  SELECT id INTO cand_id FROM candidatos WHERE slug = 'ataides-oliveira';

  IF cand_id IS NULL THEN
    RAISE NOTICE 'ataides-oliveira: pos-condicao pulada porque candidato nao existe neste banco local/CI minimo';
    RETURN;
  END IF;

  SELECT count(*) INTO total_count
  FROM projetos_lei
  WHERE candidato_id = cand_id;

  SELECT count(*) INTO target_count
  FROM projetos_lei
  WHERE candidato_id = cand_id
    AND fonte = 'Senado'
    AND proposicao_id_api IN ('100717', '101338', '101512', '101648', '101965', '111374', '112487', '113004', '113027', '113194', '113195', '113843', '121032', '121033', '121035', '121036', '121037', '121063', '122738', '123500', '124754', '125356', '125499', '125695', '127256', '127686', '129370', '130914', '133248', '133480', '133963', '134948', '134952', '134954', '135007');

  SELECT count(*) INTO scope_count
  FROM projetos_lei
  WHERE candidato_id = cand_id
    AND coverage_id = 'ataides-oliveira-senado-completo-autoria-substantiva-2011-2018-20260505'
    AND coverage_scope = 'inventario_completo_senado_autoria_substantiva_2011_2018_20260505';

  SELECT count(*) INTO lme_count
  FROM legislacao_mandato_executivo
  WHERE candidato_id = cand_id;

  IF target_count <> 35 THEN
    RAISE EXCEPTION 'Pos-apply ataides-oliveira: esperadas 35 rows alvo Senado em projetos_lei, encontradas %', target_count;
  END IF;

  IF total_count <> 35 THEN
    RAISE EXCEPTION 'Pos-apply ataides-oliveira: total projetos_lei esperado 35, encontrado %', total_count;
  END IF;

  IF scope_count <> 35 THEN
    RAISE EXCEPTION 'Pos-apply ataides-oliveira: esperadas 35 rows com coverage_id/scope alvo, encontradas %', scope_count;
  END IF;

  IF lme_count <> 0 THEN
    RAISE EXCEPTION 'Pos-apply ataides-oliveira: legislacao_mandato_executivo deve permanecer 0, encontrado %', lme_count;
  END IF;

  RAISE NOTICE 'Pos-apply ataides-oliveira Senado Lote A: projetos_lei=% coverage_scope=% legislacao_mandato_executivo=%', total_count, scope_count, lme_count;
END $$;
